const body = $input.first().json.body || {};
const action = body.action;
const allowed = ['pipeline_update','lead_create','lead_update','outreach_update','campaign_create','campaign_update','campaign_delete','campaign_restore','lead_delete','lead_restore','pipeline_delete','pipeline_restore','config_update','lead_purge','pipeline_purge','pipeline_extra','analizar_lead'];
if (!allowed.includes(action)) throw new Error('Invalid action: ' + action);
if (!body.leadId && action !== 'lead_create' && !action.startsWith('campaign_') && action !== 'config_update') throw new Error('leadId required');
return [{ json: { action, data: body } }];

const d = $json.data;
const body = {
  range: 'pipeline!A:K',
  majorDimension: 'ROWS',
  values: [[
    d.leadId,
    d.empresa || '',
    d.estado || '',
    d.prioridad || '',
    d.canalPrincipal || '',
    d.fechaPrimerContacto || '',
    new Date().toISOString(),
    d.proximoSeguimiento || '',
    d.valorEstimado != null ? d.valorEstimado : '',
    d.responsable || '',
    d.notas || ''
  ]]
};
return [{ json: { leadId: d.leadId, body } }];

const ids = $json.values.map(r => r[0]);
const leadId = $('Build Pipeline Row').item.json.leadId;
const idx = ids.indexOf(leadId);
const body = $('Build Pipeline Row').item.json.body;
if (idx !== -1) {
  body.range = `pipeline!A${idx + 1}:K${idx + 1}`;
}
return [{ json: { rowIndex: idx, body, leadId } }];

const ids = ($json.values || []).map(r => r[0]);
const d = $('Validate').item.json.data;
const idx = ids.indexOf(d.leadId);
if (idx === -1) throw new Error('Lead not found: ' + d.leadId);
const rowNum = idx + 1;
const fieldMap = {
  empresa: 'C', nicho: 'D', ciudad: 'E', pais: 'F', direccion: 'G', telefono: 'H',
  email: 'I', web: 'J', emailContacto: 'K', whatsapp: 'L', instagram: 'M',
  facebook: 'N', linkedin: 'O', googleMaps: 'P', ratingGoogle: 'Q', numResenas: 'R',
  pageSpeedMovil: 'S', pageSpeedDesktop: 'T', tieneSSL: 'U', diagnosticoIA: 'V',
  score: 'W', fuente: 'X', notas: 'Y', screenshotUrl: 'Z', cargo: 'AI', etiquetas: 'AJ'
};
const updates = [];
for (const [key, col] of Object.entries(fieldMap)) {
  if (d[key] !== undefined) {
    updates.push({ range: `prospects!${col}${rowNum}`, values: [[d[key]]] });
  }
}
return [{ json: { body: { valueInputOption: 'USER_ENTERED', data: updates } } }];

const ids = ($json.values || []).map(r => r[0]);
