    updates.push({ range: `outreach!${col}${rowNum}`, values: [[d[key]]] });
  }
}
return [{ json: { body: { valueInputOption: 'USER_ENTERED', data: updates } } }];

const d = $json.data;
const id = d.id || ('C-' + Date.now());
const now = new Date().toISOString();
const body = {
  range: 'campaigns!A:O',
  majorDimension: 'ROWS',
  values: [[
    id,
    d.nombre || '',
    d.nicho || '',
    d.idioma || 'es',
    d.estado || 'borrador',
    d.tipoMensaje || 'email',
    d.template || '',
    Array.isArray(d.leadIds) ? d.leadIds.join(',') : (d.leadIds || ''),
    now,
    d.fechaInicio || '',
    d.fechaFin || '',
    d.totalLeads != null ? d.totalLeads : (Array.isArray(d.leadIds) ? d.leadIds.length : 0),
    d.enviados != null ? d.enviados : 0,
    d.respondidos != null ? d.respondidos : 0,
    d.notas || ''
  ]]
};
return [{ json: { id, body } }];

const ids = ($json.values || []).map(r => r[0]);
const d = $('Validate').item.json.data;
const idx = ids.indexOf(d.id);
if (idx === -1) throw new Error('Campaign not found: ' + d.id);
const rowNum = idx + 1;
const fieldMap = {
  nombre: 'B', nicho: 'C', idioma: 'D', estado: 'E', tipoMensaje: 'F', template: 'G',
  fechaInicio: 'J', fechaFin: 'K', totalLeads: 'L', enviados: 'M', respondidos: 'N', notas: 'O'
};
const updates = [];
for (const [key, col] of Object.entries(fieldMap)) {
  if (d[key] !== undefined) updates.push({ range: `campaigns!${col}${rowNum}`, values: [[d[key]]] });
}
if (d.leadIds !== undefined) {
  const val = Array.isArray(d.leadIds) ? d.leadIds.join(',') : d.leadIds;
  updates.push({ range: `campaigns!H${rowNum}`, values: [[val]] });
}
return [{ json: { body: { valueInputOption: 'USER_ENTERED', data: updates } } }];

const ids = ($json.values || []).map(r => r[0]);
const d = $('Validate').item.json.data;
const idx = ids.indexOf(d.id);
if (idx === -1) throw new Error('Campaign not found: ' + d.id);
const rowNum = idx + 1;
const body = { valueInputOption: 'USER_ENTERED', data: [{ range: `campaigns!E${rowNum}`, values: [['eliminada']] }] };
return [{ json: { body } }];

const values = $json.values || [];
const d = $('Validate').item.json.data;
const claves = values.map(r => r[0]);
const idx = claves.indexOf(d.clave);
if (idx === -1) {
  return [{ json: { mode: 'append', body: { range: 'config!A:B', majorDimension: 'ROWS', values: [[d.clave, d.valor]] } } }];
}
const rowNum = idx + 1;
return [{ json: { mode: 'update', body: { valueInputOption: 'USER_ENTERED', data: [{ range: `config!B${rowNum}`, values: [[d.valor]] }] } } }];

const action = $('Validate').item.json.action;
const d = $('Validate').item.json.data;
const ids = ($json.values || []).map(r => r[0]);
const idx = ids.indexOf(d.leadId);
if (idx === -1) throw new Error('Lead no encontrado: ' + d.leadId);
const rowNum = idx + 1;
const isRestore = action === 'lead_restore';
const now = new Date().toISOString();
const body = { valueInputOption: 'USER_ENTERED', data: [
  { range: `prospects!AF${rowNum}`, values: [[isRestore ? '' : now]] },
  { range: `prospects!AG${rowNum}`, values: [[isRestore ? '' : (d.eliminadoPor || 'CRM')]] },
] };
return [{ json: { body } }];

