const ids = ($json.values || []).map(r => r[0]);
const d = $('Validate').item.json.data;
const idx = ids.indexOf(d.leadId);
if (idx === -1) throw new Error('Pipeline no encontrado: ' + d.leadId);
const rowNum = idx + 1;
const fieldMap = { probabilidad: 'O', fechaCierreEstimada: 'P' };
const updates = [];
for (const [k, col] of Object.entries(fieldMap)) {
  if (d[k] !== undefined) updates.push({ range: `pipeline!${col}${rowNum}`, values: [[d[k]]] });
}
return [{ json: { body: { valueInputOption: 'USER_ENTERED', data: updates } } }];

const values = $json.values || [];
const ids = values.map(r => r[0]);
const d = $('Validate').item.json.data;
const idx = ids.indexOf(d.leadId);
if (idx === -1) throw new Error('Lead no encontrado: ' + d.leadId);
const row = idx + 1;

const lead = {
  empresa: d.empresa || '',
  nicho: d.nicho || '',
  web: d.web || '',
  score: d.score ?? '',
  pageSpeedMovil: d.pageSpeedMovil ?? '',
  pageSpeedDesktop: d.pageSpeedDesktop ?? '',
  tieneSSL: d.tieneSSL ?? '',
  ratingGoogle: d.ratingGoogle ?? '',
  numResenas: d.numResenas ?? '',
  diagnosticoIA: d.diagnosticoIA || '',
  notas: d.notas || '',
};

const prompt = `Eres un consultor senior de ventas B2B para JD Developer, una agencia que vende diseno/desarrollo de sitios web y automatizacion a negocios locales. Analiza este lead y da una evaluacion accionable para el vendedor.

Datos del lead:
- Empresa: ${lead.empresa}
- Nicho: ${lead.nicho}
- Sitio web: ${lead.web || 'no tiene'}
- Score inicial (0-100): ${lead.score}
- PageSpeed movil: ${lead.pageSpeedMovil}
- PageSpeed desktop: ${lead.pageSpeedDesktop}
- Tiene SSL: ${lead.tieneSSL}
- Rating Google: ${lead.ratingGoogle} (${lead.numResenas} resenas)
- Diagnostico previo: ${lead.diagnosticoIA || 'ninguno'}
- Notas del vendedor: ${lead.notas || 'ninguna'}

Responde UNICAMENTE con un objeto JSON valido, sin texto adicional ni markdown, con este formato exacto:
{"scoreIA": <entero 0-100, que tan buen prospecto es para JD Developer>, "observaciones": "<1-2 lineas sobre el estado actual del negocio/sitio>", "recomendaciones": "<1-2 lineas de proximo paso concreto de venta>", "oportunidades": "<1-2 lineas de que servicios venderle>", "errores": "<1-2 lineas de problemas detectados, o 'ninguno detectado'>"}`;

const body = { model: 'claude-sonnet-4-6', max_tokens: 500, messages: [{ role: 'user', content: prompt }] };
return { json: { row, leadId: d.leadId, anthropic_body: JSON.stringify(body) } };

const text = ($json.content && $json.content[0] && $json.content[0].text) || '';
let parsed = null;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  try { parsed = m ? JSON.parse(m[0]) : null; } catch(e2) { parsed = null; }
}
if (!parsed) throw new Error('Respuesta IA invalida');
const prev = $('Build Analizar Prompt').item.json;
const scoreIA = typeof parsed.scoreIA === 'number' ? parsed.scoreIA : parseFloat(parsed.scoreIA);
return { json: {
  row: prev.row,
  leadId: prev.leadId,
  scoreIA: isNaN(scoreIA) ? null : scoreIA,
  observaciones: parsed.observaciones || '',
  recomendaciones: parsed.recomendaciones || '',
  oportunidades: parsed.oportunidades || '',
  errores: parsed.errores || '',
} };

const d = $json;
const fieldMap = { scoreIA: 'AK', observaciones: 'AL', recomendaciones: 'AM', oportunidades: 'AN', errores: 'AO' };
const updates = [];
for (const [k, col] of Object.entries(fieldMap)) {
  if (d[k] !== undefined && d[k] !== null) updates.push({ range: `prospects!${col}${d.row}`, values: [[d[k]]] });
}
return [{ json: { result: d, body: { valueInputOption: 'USER_ENTERED', data: updates } } }];
